class Solution {
public:
    int findIntegers(int n) {
        int dp[32] = {0};
        dp[0] = 1;
        dp[1] = 2;
        for (int i = 2; i <= 31; ++i) {
            dp[i] = dp[i - 1] + dp[i - 2];
        }
        int count = 0;
        for (int i = 0; i <= n; ++i) {
            int temp = i;
            bool flag = false;
            while (temp > 0) {
                if ((temp & 1) && ((temp >> 1) & 1)) {
                    flag = true;
                    break;
                }
                temp >>= 1;
            }
            if (!flag) {
                count++;
            }
        }
        return count;
    }
};
